const lockExpiredRuntimeResumeGrants = `-- name: LockExpiredRuntimeResumeGrants :many
SELECT id, run_id, attempt_id, lease_id, fencing_token, agent_id, node_id, worker_id, source_session_id, source_credential_id, target_session_id, target_credential_id, permission, granted_by_core_instance_id, granted_at, expires_at, first_used_at, revoked_at, revoked_by_type, revoked_by_id, revoke_reason
FROM runtime_resume_grants
WHERE revoked_at IS NULL
  AND expires_at <= clock_timestamp()
ORDER BY expires_at ASC, id ASC
LIMIT $1
FOR UPDATE SKIP LOCKED
`

func (q *Queries) LockExpiredRuntimeResumeGrants(ctx context.Context, batchLimit int32) ([]RuntimeResumeGrant, error) {
	rows, err := q.db.Query(ctx, lockExpiredRuntimeResumeGrants, batchLimit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []RuntimeResumeGrant
	for rows.Next() {
		var i RuntimeResumeGrant
		if err := rows.Scan(
			&i.ID,
			&i.RunID,
			&i.AttemptID,
			&i.LeaseID,
			&i.FencingToken,
			&i.AgentID,
			&i.NodeID,
			&i.WorkerID,
			&i.SourceSessionID,
			&i.SourceCredentialID,
			&i.TargetSessionID,
			&i.TargetCredentialID,
			&i.Permission,
			&i.GrantedByCoreInstanceID,
			&i.GrantedAt,
			&i.ExpiresAt,
			&i.FirstUsedAt,
			&i.RevokedAt,
			&i.RevokedByType,
			&i.RevokedByID,
			&i.RevokeReason,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

